{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-compressor-evidence-gap-partial-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的压缩机 compressor-1 的出口压力目标过近问题生成候选提案；由于诊断同时提示根因可能是压比不足或缺少下游背压数据，以下仅提出局部、可审查的非执行式占位修补。",
      "issues": [
        {
          "title": "压缩机出口压力目标与入口压力过近",
          "detail": "compressor-1 当前 outlet_pressure_target_kpa=235，而入口流股 feed-3 的 pressure_kpa=220；现有错误诊断直接指出该目标过近，难以解释所请求的压缩负荷。",
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "根因未确认，可能缺少下游背压约束",
          "detail": "警告诊断指出当前残差模式既可能来自压比不足，也可能来自缺失的下游背压数据，因此不宜直接做显著拓扑或强假设修改。",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 compressor-1 的出口压力目标改为待确认占位值",
          "target": {
            "type": "unit",
            "id": "compressor-1"
          },
          "rationale": "错误诊断直接指向当前出口压力目标过近。为避免在根因未确认时臆造具体新设定，可先把过近的固定目标替换为需要工艺确认的占位规格，使审查者决定合适的出口压力或压比。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "expected_type": "number",
                "reason": "当前 235 kPa 与入口 220 kPa 过近；需要根据目标压比或下游背压确认更合理的出口压力目标"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 product-3 增加下游背压/边界条件占位",
          "target": {
            "type": "stream",
            "id": "product-3"
          },
          "rationale": "警告诊断明确提示可能缺少下游背压数据。由于当前仅见到 compressor-1 出口流股 product-3 且未见任何压力规格，建议仅在该直接相关流股上补充待确认的压力边界占位，而不做拓扑重连或数值臆测。",
          "patch": {
            "spec_placeholders": [
              {
                "path": "specs.pressure_kpa",
                "expected_type": "number",
                "reason": "用于确认压缩机出口侧/下游背压边界，帮助区分压比不足与缺少背压数据"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.84,
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-unit-1",
        "flowdoc-stream-1",
        "flowdoc-stream-2",
        "snapshot-1"
      ]
    }
  ]
}
